#!/usr/bin/env node
// GEP validation helper — checks evolver workspace integrity
const fs = require('fs');
const os = require('os');
const workspace = process.env.OPENCLAW_WORKSPACE || os.homedir() + '/.claude/evolver';
const checks = [
  workspace + '/MEMORY.md',
  workspace + '/USER.md',
];
let ok = true;
for (const f of checks) {
  if (!fs.existsSync(f)) {
    console.error('MISSING: ' + f);
    ok = false;
  }
}
if (ok) { console.log('ok'); process.exit(0); }
else { process.exit(1); }
EOF
